)
$ErrorActionPreference="Stop"
. (Join-Path $PSScriptRoot "LiveVerification.Common.ps1"); $env:FLOWPLANE_ROOT=$FlowplaneRoot; $env:FLOWPLANE_DEMO_OUTPUT_ROOT=Join-Path $OutputRoot "adapter-private"; . (Join-Path $PSScriptRoot "..\FlowplaneDemo.Common.ps1")
$run=[DateTime]::UtcNow.ToString("yyyyMMddTHHmmssZ").ToLowerInvariant();$bundle=Join-Path $OutputRoot $run;New-Item -ItemType Directory -Force -Path (Join-Path $bundle "actual"),(Join-Path $bundle "logs")|Out-Null
$runtimeId="gcp-pubsub-evidence-$run";$registration="flowplane-gcp-register-$run";$emulator="flowplane-gcp-pubsub-emulator-$run";$bridge="flowplane-gcp-eventarc-$run";$function="flowplane-gcp-pubsub-function-$run"
$input="fp-raw-$run";$output="fp-output-$run";$dlq="fp-dlq-$run";$token=New-FlowplaneAccessToken
function Invoke-Api([string]$Method,[string]$Path,$Body=$null){$h=@{Authorization="Bearer $token";tenantId="acme-corp";"X-Tenant-Id"="acme-corp"};$r=@{Method=$Method;Uri="http://127.0.0.1:8081$Path";Headers=$h;TimeoutSec=30};if($null-ne$Body){$r.ContentType="application/json";$r.Body=$Body|ConvertTo-Json -Depth 20 -Compress};Invoke-RestMethod @r}
$started=[Collections.Generic.List[string]]::new()
try{
  $probe=Get-Content -LiteralPath (Join-Path $FixtureRoot "valid-input.jsonl") -TotalCount 1
  docker run -d --name $emulator --network flowplane-quality-stack_default --network-alias pubsub-emulator -p "127.0.0.1::8085" gcr.io/google.com/cloudsdktool/google-cloud-cli:emulators gcloud beta emulators pubsub start --project=flowplane-local --host-port=0.0.0.0:8085|Out-Null;$started.Add($emulator)
  $bridgeScript=Join-Path $PSScriptRoot "assets\serverless-event-node\gcp-eventarc-bridge.mjs"
  docker run -d --name $bridge --network flowplane-quality-stack_default --network-alias eventarc-bridge -v "$bridgeScript`:/app/bridge.mjs:ro" -e "FUNCTION_TARGET_URL=http://$function`:8080/" node:22-alpine node /app/bridge.mjs|Out-Null;$started.Add($bridge)
  docker run -d --name $function --network flowplane-quality-stack_default -p "127.0.0.1::8080" -e "PUBSUB_EMULATOR_HOST=pubsub-emulator:8085" -e "FLOWPLANE_GCP_PROJECT_ID=flowplane-local" -e "FLOWPLANE_GCP_OUTPUT_TOPIC=$output" -e "FLOWPLANE_GCP_DLQ_TOPIC=$dlq" -e "FLOWPLANE_SERVERLESS_CONTROL_PLANE_URL=http://flowplane-backend:8080" -e "FLOWPLANE_SERVERLESS_TENANT_ID=acme-corp" -e "FLOWPLANE_SERVERLESS_RUNTIME_ID=$runtimeId" -e "FLOWPLANE_SERVERLESS_RUNTIME_NAME=GCP PubSub CloudEvent Evidence" -e "FLOWPLANE_SERVERLESS_AUTH_TOKEN=$token" -e "FLOWPLANE_SERVERLESS_IN_PROCESS_CONTROL_AGENTS=true" -e "FLOWPLANE_SERVERLESS_ASSIGNMENT_POLL_INTERVAL_MS=1000" flowplane-gcp-pubsub-local|Out-Null;$started.Add($function)
  Start-Sleep 12;$emulatorPort=[int]((docker port $emulator "8085/tcp"|Select-Object -First 1)-replace'^.*:','');$env:PUBSUB_EMULATOR_HOST="127.0.0.1:$emulatorPort"
  $setup=Join-Path $PSScriptRoot "assets\serverless-event-node\gcp-pubsub-setup.mjs";$oldPreference=$ErrorActionPreference;$ErrorActionPreference="Continue";try{& node $setup flowplane-local $input $output $dlq 2>&1|Out-Null;$setupExit=$LASTEXITCODE}finally{$ErrorActionPreference=$oldPreference};if($setupExit-ne0){throw"Pub/Sub topic setup failed."}
  $functionPort=[int]((docker port $function "8080/tcp"|Select-Object -First 1)-replace'^.*:','');$encoded=[Convert]::ToBase64String([Text.Encoding]::UTF8.GetBytes([string]$probe));$cloudEventBody=@{message=@{data=$encoded;messageId="registration-$run"};subscription="local-registration"}|ConvertTo-Json -Depth 5 -Compress;$cloudHeaders=@{"ce-id"="registration-$run";"ce-source"="//pubsub.googleapis.com/projects/flowplane-local/topics/$input";"ce-specversion"="1.0";"ce-type"="google.cloud.pubsub.topic.v1.messagePublished"}
  try{Invoke-WebRequest -UseBasicParsing -Method Post -Uri "http://127.0.0.1:$functionPort/" -Headers $cloudHeaders -ContentType "application/json" -Body $cloudEventBody -TimeoutSec 30|Out-Null}catch{}
  $deadline=(Get-Date).AddMinutes(2);do{try{$runtime=Invoke-Api GET "/api/v1/runtimes/$runtimeId"}catch{};if($runtime -and $runtime.name -eq "GCP PubSub CloudEvent Evidence"){break};Start-Sleep 2}while((Get-Date)-lt$deadline);if(-not$runtime-or$runtime.name-ne"GCP PubSub CloudEvent Evidence"){throw"Actual PubSub function instance did not register."}
  Invoke-Api POST "/api/v1/mappings/6a5efccf8dd158f5c96318e2/deploy" @{runtimeIds=@($runtimeId);rolloutPercent=100;requireReplayGate=$false;reason="Restore assignment after PubSub function registration";changeTicket="GCPPUBSUB-FUNCTION-$run"}|Out-Null
  Start-Sleep -Seconds 7
  $deadline=(Get-Date).AddMinutes(2);do{try{Invoke-WebRequest -UseBasicParsing -Method Post -Uri "http://127.0.0.1:$functionPort/" -Headers $cloudHeaders -ContentType "application/json" -Body $cloudEventBody -TimeoutSec 30|Out-Null}catch{};$runtime=Invoke-Api GET "/api/v1/runtimes/$runtimeId";if($runtime.activeArtifactId){break};Start-Sleep 2}while((Get-Date)-lt$deadline);if(-not$runtime.activeArtifactId){throw"PubSub function instance did not acknowledge its mapping."}
  $client=Join-Path $PSScriptRoot "assets\serverless-event-node\gcp-pubsub-proof.mjs";$oldPreference=$ErrorActionPreference;$ErrorActionPreference="Continue";try{$clientOutput=& node $client flowplane-local $input $output $dlq $FixtureRoot $bundle 2>&1;$clientExit=$LASTEXITCODE}finally{$ErrorActionPreference=$oldPreference};if($clientExit-ne0){throw($clientOutput-join"`n")}
  & node (Join-Path $PSScriptRoot "assets\serverless-event-node\validate-trigger-output.mjs") $FixtureRoot $bundle (Join-Path $PSScriptRoot "..\..\..\artifacts\live-local-verification\evidence\integration-proofs\serverless-azure\20260721T045510Z\expected\simulation-batch.json") | Out-Null;if($LASTEXITCODE-ne0){throw"GCP PubSub content validation failed."}
  $oldPreference=$ErrorActionPreference;$ErrorActionPreference="Continue";try{foreach($pair in @(@($emulator,"pubsub-emulator"),@($bridge,"eventarc-bridge"),@($function,"gcp-function"))){docker logs $pair[0] 2>&1|Set-Content -Encoding utf8 (Join-Path $bundle "logs\$($pair[1]).log")}}finally{$ErrorActionPreference=$oldPreference}
  Write-JsonFile (Join-Path $bundle "proof-manifest.json") ([ordered]@{status="PASS";runId=$run;trigger="GCP Pub/Sub CloudEvent";runtimeId=$runtimeId;artifactId=$runtime.activeArtifactId;artifactHash=$runtime.activeArtifactHash;validRecords=100;invalidRecords=10;sourceBoundary="Verifier writes only the Pub/Sub emulator input topic";sinkBoundary="CloudEvent handler publishes transformed and DLQ Pub/Sub topics";eventarcBoundary="Local bridge converts the emulator push envelope to the standard binary CloudEvent envelope; it performs no transformation or result publishing";emulatorImage=(docker inspect $emulator --format '{{.Image}}');functionImage=(docker inspect $function --format '{{.Image}}');completedAt=[DateTime]::UtcNow.ToString("o")});Write-Output "PASS $bundle"
}finally{Remove-Item Env:PUBSUB_EMULATOR_HOST -ErrorAction SilentlyContinue;$oldPreference=$ErrorActionPreference;$ErrorActionPreference="Continue";try{foreach($container in @($function,$bridge,$emulator,$registration)){if(docker ps -aq --filter "name=^$container$"){docker logs $container 2>&1|Set-Content -Encoding utf8 (Join-Path $bundle "logs\$container-final.log");docker rm -f $container|Out-Null}}}finally{$ErrorActionPreference=$oldPreference}}
